{action_set_definitions}: {
  "get_site_state": {
    "description": "Queries the current environment state for specific categories such as 'environmental_conditions', 'grid_layout', or 'site_resources'.",
    "parameters": {
      "type": "object",
      "properties": {
        "category": {
          "type": "string",
          "enum": [
            "grid_layout",
            "available_teams",
            "site_resources",
            "environmental_conditions"
          ],
          "description": "The category of state information to retrieve."
        }
      },
      "required": [
        "category"
      ]
    },
    "example_output": {
      "environmental_conditions": {
        "temperature_c": 15.5,
        "pressure_hpa": 1013.2,
        "wind_speed": 5.0
      }
    }
  },
  "get_project_config": {
    "description": "Retrieves the required synchronization protocols and data-entry standards for a specific job archive.",
    "parameters": {
      "type": "object",
      "properties": {
        "archive_id": {
          "type": "string",
          "description": "The name of the digital job file/archive (e.g., 'BARROW_A_ARCHIVE')."
        }
      },
      "required": [
        "archive_id"
      ]
    },
    "example_output": {
      "protocol_id": "ISO-ARCH-2023-B",
      "sync_token": "SYNC_99210"
    }
  },
  "set_instrument_atmospherics": {
    "description": "Configures the Total Station with real-time temperature and pressure to ensure EDM accuracy.",
    "parameters": {
      "type": "object",
      "properties": {
        "temperature": {
          "type": "number",
          "description": "Temperature in Celsius."
        },
        "pressure": {
          "type": "number",
          "description": "Atmospheric pressure in hPa."
        }
      },
      "required": [
        "temperature",
        "pressure"
      ]
    },
    "example_output": {
      "status": "success",
      "ppm_correction": 12.5
    }
  },
  "sync_entry_protocol": {
    "description": "Synchronizes the local data-entry system with the project's central database using a protocol ID.",
    "parameters": {
      "type": "object",
      "properties": {
        "protocol_id": {
          "type": "string",
          "description": "The ID or token retrieved from project configuration."
        }
      },
      "required": [
        "protocol_id"
      ]
    },
    "example_output": {
      "synchronized": true,
      "mode": "High-Precision-Validation"
    }
  },
  "take_measurement": {
    "description": "Triggers the Total Station to measure the coordinate of a target point.",
    "parameters": {
      "type": "object",
      "properties": {
        "point_id": {
          "type": "string",
          "description": "Identifier for the grid point."
        },
        "target_northing": {
          "type": "number",
          "description": "Target N coordinate."
        },
        "target_easting": {
          "type": "number",
          "description": "Target E coordinate."
        }
      },
      "required": [
        "point_id",
        "target_northing",
        "target_easting"
      ]
    },
    "example_output": {
      "actual_n": 1200.001,
      "actual_e": 1500.002,
      "horizontal_residual": 0.002
    }
  },
  "archive_measurement": {
    "description": "Permanently commits the verified measurement data to the digital job archive.",
    "parameters": {
      "type": "object",
      "properties": {
        "archive_id": {
          "type": "string",
          "description": "Target archive name."
        },
        "point_id": {
          "type": "string",
          "description": "Identifier for the grid point."
        },
        "measurement_data": {
          "type": "object",
          "description": "The coordinate and residual data to store."
        }
      },
      "required": [
        "archive_id",
        "point_id",
        "measurement_data"
      ]
    },
    "example_output": {
      "transaction_id": "TXN_BARROW_001",
      "status": "COMMITTED"
    }
  }
}
